detailed_optimizations.code_changes:
将 kernel 参数改为扁平 1D 指针并添加 restrict/assume_aligned，减少别名分析障碍；把常量提取到局部变量；保留 j 为内层循环以匹配行主序。示例：

void kernel_fdtd_2d_opt(int tmax, int nx, int ny,
    DATA_TYPE * __restrict ex,
    DATA_TYPE * __restrict ey,
    DATA_TYPE * __restrict hz,
    DATA_TYPE * __restrict fict) {
  const DATA_TYPE c1 = SCALAR_VAL(0.5);
  const DATA_TYPE c2 = SCALAR_VAL(0.7);
  for (int t = 0; t < tmax; ++t) {
    DATA_TYPE ft = fict[t];
    DATA_TYPE * __restrict ey0 = ey;
    #pragma omp simd
    for (int j = 0; j < ny; ++j) ey0[j] = ft;

    for (int i = 1; i < nx; ++i) {
      DATA_TYPE * __restrict ey_i   = ey + (size_t)i * ny;
      DATA_TYPE * __restrict hz_i   = hz + (size_t)i * ny;
      DATA_TYPE * __restrict hz_im1 = hz + (size_t)(i - 1) * ny;
      #pragma omp simd
      for (int j = 0; j < ny; ++j)
        ey_i[j] -= c1 * (hz_i[j] - hz_im1[j]);
    }

    for (int i = 0; i < nx; ++i) {
      DATA_TYPE * __restrict ex_i = ex + (size_t)i * ny;
      DATA_TYPE * __restrict hz_i = hz + (size_t)i * ny;
      #pragma omp simd
      for (int j = 1; j < ny; ++j)
        ex_i[j] -= c1 * (hz_i[j] - hz_i[j - 1]);
    }

    for (int i = 0; i < nx - 1; ++i) {
      DATA_TYPE * __restrict hz_i   = hz + (size_t)i * ny;
      DATA_TYPE * __restrict ex_i   = ex + (size_t)i * ny;
      DATA_TYPE * __restrict ey_i   = ey + (size_t)i * ny;
      DATA_TYPE * __restrict ey_ip1 = ey + (size_t)(i + 1) * ny;
      #pragma omp simd
      for (int j = 0; j < ny - 1; ++j)
        hz_i[j] -= c2 * (ex_i[j + 1] - ex_i[j] + ey_ip1[j] - ey_i[j]);
    }
  }
}

同时建议编译选项使用 -O3 -march=native -ffast-math（若允许数值语义放宽）并检查向量化报告。

对 ey/ex/hz 三个阶段采用块化处理，使相邻行的 hz、ey、ex 更可能驻留在 LLC/L2 中。由于 hz 更新依赖 ex[i][j+1] 和 ey[i+1][j]，推荐按 i 方向分块，必要时结合 j 方向块。示例框架：

const int Bi = 32;
for (int t = 0; t < tmax; ++t) {
  #pragma omp simd
  for (int j = 0; j < ny; ++j) ey[j] = fict[t];

  for (int ii = 1; ii < nx; ii += Bi) {
    int iend = (ii + Bi < nx) ? ii + Bi : nx;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 0; j < ny; ++j)
        ey[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[(i-1)*ny + j]);
  }

  for (int ii = 0; ii < nx; ii += Bi) {
    int iend = (ii + Bi < nx) ? ii + Bi : nx;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 1; j < ny; ++j)
        ex[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[i*ny + j - 1]);
  }

  for (int ii = 0; ii < nx - 1; ii += Bi) {
    int iend = (ii + Bi < nx - 1) ? ii + Bi : nx - 1;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 0; j < ny - 1; ++j)
        hz[i*ny + j] -= 0.7 * (ex[i*ny + j + 1] - ex[i*ny + j] + ey[(i+1)*ny + j] - ey[i*ny + j]);
  }
}

Bi 需要通过 profiling 调优，通常 16/32/64 行较合适。

时间步 t 不能并行，但每个 t 内的三个空间更新阶段可分别并行。建议在每个阶段使用 #pragma omp parallel for schedule(static)，并保留阶段间隐式 barrier 以满足依赖。示例：

for (int t = 0; t < tmax; ++t) {
  DATA_TYPE ft = fict[t];
  #pragma omp parallel for schedule(static)
  for (int j = 0; j < ny; ++j)
    ey[j] = ft;

  #pragma omp parallel for schedule(static)
  for (int i = 1; i < nx; ++i)
    for (int j = 0; j < ny; ++j)
      ey[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[(i-1)*ny + j]);

  #pragma omp parallel for schedule(static)
  for (int i = 0; i < nx; ++i)
    for (int j = 1; j < ny; ++j)
      ex[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[i*ny + j - 1]);

  #pragma omp parallel for schedule(static)
  for (int i = 0; i < nx - 1; ++i)
    for (int j = 0; j < ny - 1; ++j)
      hz[i*ny + j] -= 0.7 * (ex[i*ny + j + 1] - ex[i*ny + j] + ey[(i+1)*ny + j] - ey[i*ny + j]);
}

若线程创建开销明显，可将 parallel 区域外提：#pragma omp parallel { for(t...) { #pragma omp for ... } }。
